import KEYS from"./visitor-keys.js";const KEY_BLACKLIST=new Set(["parent","leadingComments","trailingComments"]);function filterKey(e){return!KEY_BLACKLIST.has(e)&&"_"!==e[0]}export function getKeys(e){return Object.keys(e).filter(filterKey)}export function unionWith(e){const t=Object.assign({},KEYS);for(const r of Object.keys(e))if(Object.hasOwn(t,r)){const n=new Set(e[r]);for(const e of t[r])n.add(e);t[r]=Object.freeze(Array.from(n))}else t[r]=Object.freeze(Array.from(e[r]));return Object.freeze(t)}export{KEYS};